    .SET_COUNT         ( ICacheSets       ),
    .FETCH_AW          ( snitch_pkg::PLEN ),
    .FETCH_DW          ( 32               ),
    .FILL_AW           ( snitch_pkg::PLEN ),
    .FILL_DW           ( snitch_pkg::DLEN ),
    .EARLY_LATCH        ( 0               ),
